{
  "name": "meeting-intel-agent",
  "version": "1.0.0",
  "description": "Manual upload meeting intelligence agent with Gemini, Google Sheets, and Google Calendar",
  "type": "module",
  "main": "server.js",
  "scripts": {
    "start": "node server.js",
    "dev": "node server.js"
  },
  "dependencies": {
    "@google/generative-ai": "^0.21.0",
    "dotenv": "^16.5.0",
    "express": "^4.21.2",
    "express-session": "^1.18.1",
